 1→import type { StateCreator } from 'zustand';
 2→import {
 3→  ParameterPointsProgramResponse,
 4→  ParameterPointsProgramState,
 5→  ParameterPointsProgramStatus,
 6→} from '../models';
 7→
 8→export interface ParameterPointsProgramActions {
 9→  setStatus: (status: ParameterPointsProgramStatus) => void;
10→  setData: (data: ParameterPointsProgramResponse[]) => void;
11→  setSelectedCategory: (
12→    selectedCategory: ParameterPointsProgramResponse | undefined,
13→  ) => void;
14→  setPointsQuantity: (pointsQuantity: number) => void;
15→  setConversionFactor: (conversionFactor: number) => void;
16→  reset: () => void;
17→}
18→
19→export interface ParameterPointsProgramSlice {
20→  parameterPointsProgram: ParameterPointsProgramState;
21→  parameterPointsProgramActions: ParameterPointsProgramActions;
22→}
23→
24→const initialParameterPointsProgramState: ParameterPointsProgramState = {
25→  status: ParameterPointsProgramStatus.IDLE,
26→  data: undefined,
27→  selectedCategory: undefined,
28→  pointsQuantity: 0,
29→  conversionFactor: 0.1,
30→};
31→
32→export const createParameterPointsProgramSlice: StateCreator<
33→  ParameterPointsProgramSlice,
34→  [],
35→  [],
36→  ParameterPointsProgramSlice
37→> = set => ({
38→  parameterPointsProgram: initialParameterPointsProgramState,
39→  parameterPointsProgramActions: {
40→    setStatus: (status: ParameterPointsProgramStatus) =>
41→      set(state => ({
42→        parameterPointsProgram: {
43→          ...state.parameterPointsProgram,
44→          status,
45→        },
46→      })),
47→    setData: (data: ParameterPointsProgramResponse[]) =>
48→      set(state => ({
49→        parameterPointsProgram: {
50→          ...state.parameterPointsProgram,
51→          data,
52→          status: ParameterPointsProgramStatus.SUCCESS,
53→        },
54→      })),
55→    setSelectedCategory: (
56→      selectedCategory: ParameterPointsProgramResponse | undefined,
57→    ) =>
58→      set(state => ({
59→        parameterPointsProgram: {
60→          ...state.parameterPointsProgram,
61→          selectedCategory,
62→        },
63→      })),
64→    setPointsQuantity: (pointsQuantity: number) =>
65→      set(state => ({
66→        parameterPointsProgram: {
67→          ...state.parameterPointsProgram,
68→          pointsQuantity,
69→        },
70→      })),
71→    setConversionFactor: (conversionFactor: number) =>
72→      set(state => ({
73→        parameterPointsProgram: {
74→          ...state.parameterPointsProgram,
75→          conversionFactor,
76→        },
77→      })),
78→    reset: () =>
79→      set({
80→        parameterPointsProgram: initialParameterPointsProgramState,
81→      }),
82→  },
83→});
