 10→import { useScreenViewTracking } from '../../hooks/tracking';
 11→import { usePoints } from '../../services';
 12→
 13→import {
 14→  eventModalView,
 15→  eventScreenViewV3,
 16→  eventSelectContent,
 17→} from '~/constants/functions';
 18→import { PropsRootStack } from '../../routes/Models';
 19→import {
 20→  formatCurrencyBR,
 21→  getFormattedPoints,
 22→  getParsedCurrency,
 23→  getParsePoints,
 24→} from '../../utils/functions';
 25→import { CashbackInvoiceItem, InvoiceCashbackProps } from './models';
 26→import InvoiceCashbackPointsView from './view';
 27→
 28→const InvoiceCashbackPoints: FC<InvoiceCashbackProps> = ({ route }) => {
 29→  const {
 30→    points,
 31→    pointsQuantity,
 32→    isLoadingParameterization,
 33→    requestParameterization,
 34→  } = usePoints();
 35→  useScreenViewTracking({
 36→    route,
 37→    title: 'Cashback na fatura',
 38→  });
 39→  const { height, width } = Dimensions.get('window');
 40→
 41→  useEffect(() => {
 42→    requestParameterization();
 43→  }, [requestParameterization]);
 44→
 45→  const hasFocused = useRef(false);
 46→  useFocusEffect(
 47→    React.useCallback(() => {
 48→      if (!hasFocused.current) {
 49→        eventScreenViewV3(
 50→          'desconto_fatura',
 51→          'hub_recompensas_spmais',
 52→          'monetizacao',
 53→          {
 54→            location_1: 'monetizacao',
 55→            location_2: 'hub_recompensas_spmais',
 56→            location_3: 'desconto_fatura',
 57→          },
 58→        );
 59→        hasFocused.current = true;
 60→      }
 61→      return () => {
 62→        hasFocused.current = false;
 63→      };
 64→    }, []),
 65→  );
 66→
 67→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
 68→
 69→  const conversionFactor = route?.params?.conversionFactor ?? 0;
 70→  const pointsPrice = Number(
 71→    (Math.trunc(points || 0) * conversionFactor).toFixed(2),
 72→  );
 73→
 74→  const finalPrice = pointsPrice || 0;
 75→  const [pointsValue, setPointsValue] = useState('');
 76→  const [reaisValue, setReaisValue] = useState('');
 77→  const [pointsError, setPointsError] = useState(false);
 78→  const [reaisError, setReaisError] = useState(false);
 79→  const convertionPrice = pointsQuantity * conversionFactor;
 80→  const convertionValue = new Intl.NumberFormat('pt-BR', {
 81→    style: 'currency',
 82→    currency: 'BRL',
 83→  }).format(convertionPrice);
 84→
 85→  const handleGoBack = () => {
 86→    navigation.goBack();
 87→  };
 88→
 89→  const handleContinue = () => {
 90→    eventSelectContent({
 91→      content_type: 'cta',
 92→      content_id: 'continuar',
 93→      location_1: 'monetizacao',
 94→      location_2: 'hub_recompensas_spmais',
 95→      location_3: 'desconto_fatura',
 96→    });
 97→
 98→    const reaisValue = conversionFactor * getParsePoints(pointsValue);
 99→
100→    navigation.navigate('InvoiceCashbackSummary', {
101→      pointsSelected: getParsePoints(pointsValue),
102→      reaisSelected: reaisValue,
103→      conversionFactor,
104→      productCode: route?.params?.productCode,
105→      campaingId: route?.params?.campaingId,
106→    });
107→  };
108→
109→  const invoiceList = (): CashbackInvoiceItem[] => {
110→    return [
111→      {
