 39→export function useExtractRewardProgramScreen(
 40→  params?: ExtractRewardProgramProps,
 41→): UseExtractRewardProgramReturn {
 42→  const hasTrackedScreenView = useRef(false);
 43→  const hasTrackedSearchPress = useRef(false);
 44→  const canLoadMoreRef = useRef(false);
 45→  const isLoadingMoreRef = useRef(false);
 46→
 47→  const modalizeRefInfo = useRef<PropsModalizeRef>(
 48→    null as unknown as PropsModalizeRef,
 49→  );
