103→      };
104→    }, []),
105→  );
106→
107→  const refreshExtractData = useCallback(() => {
108→    pointsExtractActions.setExtractStatus(PointsExtractStatus.IDLE);
109→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
