111→    getPointsBalance();
112→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
113→  }, [pointsExtractActions]);
114→
115→  useFocusEffect(
116→    useCallback(() => {
117→      refreshExtractData();
118→    }, [refreshExtractData]),
119→  );
120→
121→  useEffect(() => {
122→    const shouldFetchBalance =
123→      pointsBalance.points === undefined ||
124→      pointsBalance.status === PointsBalanceStatus.ERROR;
125→
126→    if (shouldFetchBalance) {
127→      getPointsBalance();
128→    }
129→
130→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
131→  }, [
132→    pointsBalance.points,
133→    pointsBalance.status,
134→  ]);
135→
136→  useEffect(() => {
137→    if (!isLoadingExtract && isRefreshing) {
138→      setIsRefreshing(false);
139→    }
140→  }, [
141→    isLoadingExtract,
142→    isRefreshing,
143→  ]);
144→
145→  useEffect(() => {
146→    if (searchText.length === 0) {
147→      hasTrackedSearchPress.current = false;
148→    }
149→  }, [searchText]);
150→
151→  const getPointsAvailable = useMemo(() => {
152→    return pointsBalance.points ?? 0;
153→  }, [pointsBalance.points]);
154→
155→  const handleGoBack = useCallback(() => {
156→    params?.navigation?.goBack();
157→  }, [params?.navigation]);
158→
159→  const requestPointsExtract = useCallback(() => {
160→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
161→  }, []);
162→
163→  const handleLoadMore = useCallback(() => {
164→    const currentPage = pointsExtract.extractData?.pagination?.page ?? 1;
165→    const totalPages = pointsExtract.extractData?.pagination?.totalPages ?? 1;
166→    const canLoadMore =
167→      currentPage < totalPages && !pointsExtract.isLoadingMore;
168→
169→    if (canLoadMore) {
170→      getPointsExtract({ page: currentPage + 1 });
171→    }
172→  }, [
173→    pointsExtract.extractData?.pagination,
174→    pointsExtract.isLoadingMore,
175→  ]);
176→
177→  const setTransactionsFilters = useCallback(
178→    (filters: AppliedFilters) => {
179→      pointsExtractActions.setTransactionsFilters(filters);
180→    },
181→    [pointsExtractActions],
182→  );
183→
184→  const clearTransactionsFilters = useCallback(() => {
185→    pointsExtractActions.clearTransactionsFilters();
186→  }, [pointsExtractActions]);
187→
188→  const getTransactionsWithFilters = useCallback(
189→    (transactions: PointsTransaction[]): PointsTransaction[] => {
190→      let filtered = transactions;
191→
192→      if (appliedTransactionsFilters) {
193→        const filtersWithDays: AppliedFilters = {
194→          ...appliedTransactionsFilters,
195→          period:
196→            appliedTransactionsFilters.period !== undefined
197→              ? PERIOD_DAYS_MAP[appliedTransactionsFilters.period]
198→              : undefined,
199→        };
200→        filtered = getFilteredTransactions(filtered, filtersWithDays);
201→      }
202→
203→      return filtered;
204→    },
205→    [appliedTransactionsFilters],
206→  );
207→
208→  const getExtractData = useMemo(() => {
209→    if (!pointsExtract.extractData) return undefined;
210→
211→    const transactions = getTransactionsWithFilters(
212→      pointsExtract.extractData.transactions,
213→    );
214→
215→    return {
216→      ...pointsExtract.extractData,
217→      transactions,
218→    };
219→  }, [
220→    pointsExtract.extractData,
221→    getTransactionsWithFilters,
222→  ]);
223→
224→  const getTransactionsData = useMemo(() => {
225→    if (!getExtractData?.transactions) {
226→      return [];
227→    }
228→
229→    if (debouncedSearchText && debouncedSearchText.trim() !== '') {
230→      return getFilteredTransactionsByText(
231→        getExtractData.transactions,
232→        debouncedSearchText,
233→        false,
234→      );
235→    }
236→
237→    return getExtractData.transactions;
238→  }, [
239→    getExtractData?.transactions,
240→    debouncedSearchText,
241→  ]);
242→
243→  useEffect(() => {
244→    if (!getExtractData) return;
245→
246→    let cancelled = false;
